#include <bits/stdc++.h>
using namespace std;

const int N=25;

struct Edge{
	int u,v,w;
}edge[N];

bool cmp(Edge x,Edge y){
	return x.w<y.w;
}

int T,n,m,s,ans,f[N];
int head[N],ver[N<<1],dis[N<<1],nxt[N<<1],tot;

void add(int u,int v,int w){
	ver[++tot]=v,dis[tot]=w,nxt[tot]=head[u],head[u]=tot;
	ver[++tot]=u,dis[tot]=w,nxt[tot]=head[v],head[v]=tot;
}

int dfs(int x,int en,int in_edge){
	if(x==en)
		return 1;
	int res=0;
	for(int i=head[x];i;i=nxt[i])
		if(i!=(in_edge^1) && ver[i]){
			int tmp=dfs(ver[i],en,i);
			if(tmp && max(dis[tmp],dis[i])>dis[res])
				res=(dis[tmp]>dis[i]?tmp:i);
		}
	return res;
}

int father(int x){
	return f[x]==x?x:f[x]=father(f[x]);
}

int main(){
	dis[0]=-1e8;
	scanf("%d",&T);
	while(T--){
		scanf("%d",&m);
		map<string,int> mp;
		tot=1;
		memset(head,0,sizeof(head));
		n=0;
		ans=0;
		mp["Park"]=++n;
		for(int i=1;i<=m;i++){
			string a,b;
			int w;
			cin>>a>>b>>w;
			if(mp.find(a)==mp.end())
				mp[a]=++n;
			if(mp.find(b)==mp.end())
				mp[b]=++n;
			edge[i]={mp[a],mp[b],w};
		}
		scanf("%d",&s);
		for(int i=1;i<=n;i++)
			f[i]=i;
		sort(edge+1,edge+m+1,cmp);
		for(int i=1;i<=m;i++){
			if(edge[i].u==1 || edge[i].v==1)
				continue;
			int fu=father(edge[i].u),fv=father(edge[i].v);
			if(fu!=fv){
				add(edge[i].u,edge[i].v,edge[i].w);
				//printf("%d %d %d\n",edge[i].u,edge[i].v,edge[i].w);
				ans+=edge[i].w;
				f[fv]=fu;
			}
		}
		for(int i=1;i<=m && s;i++){
			if(edge[i].u!=1 && edge[i].v!=1)
				continue;
			if(edge[i].u>edge[i].v)
				swap(edge[i].u,edge[i].v);
			int x=edge[i].v,w=edge[i].w;
			int p=dfs(1,x,0);
			//printf("%d\n",dis[p]);
			if(dis[p]<=w && p>0)
				continue;
			//printf("Delet: (%d, %d, %d)\n",ver[p^1],ver[p],edge[p]);
			ver[p]=ver[p^1]=0;
			ans-=max(0,dis[p]);
			add(1,x,w);
			//printf("Add: (1, %d, %d)\n",x,w);
			ans+=w,s--;
		}
		printf("Total miles driven: %d\n\n",ans);
	}
	return 0;
}
